import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { first } from 'rxjs/operators';
import { Account } from '@app/_models';
import { AccountService, AlertService } from '@app/_services';
import { AlertComponent } from '@app/_components/alert.component';

@Component({
  templateUrl: 'list.component.html',
  standalone: true,
  imports: [CommonModule, RouterLink, AlertComponent]
})
export class ListComponent implements OnInit {
  accounts: Account[] = [];
  loading = true;
  error: string | null = null;

  constructor(private accountService: AccountService, private alertService: AlertService) { }

  ngOnInit() {
    console.log('=== LIST COMPONENT INITIALIZED ===');
    this.loadAccounts();
  }

  loadAccounts() {
    this.loading = true;
    this.error = null;
    
    console.log('Calling accountService.getAll()...');
    
    // Log the service to make sure it's available
    console.log('AccountService:', this.accountService);
    
    const subscription = this.accountService.getAll()
      .pipe(first())
      .subscribe({
        next: (accounts) => {
          console.log('✅ SUCCESS: Accounts loaded:', accounts);
          console.log('📊 Number of accounts:', accounts?.length || 0);
          this.accounts = accounts || [];
          this.loading = false;
        },
        error: (error) => {
          console.error('❌ ERROR: Failed to load accounts');
          console.error('Error details:', error);
          const errorMessage = error.error?.message || error.message || 'Failed to load accounts';
          this.error = errorMessage;
          this.loading = false;
          this.alertService.error(errorMessage);
        }
      });
    
    console.log('Subscription created:', subscription);
  }

  deleteAccount(account: Account) {
    if (!confirm(`Are you sure you want to delete ${account.firstName} ${account.lastName}?`)) {
      return;
    }
    
    account.isDeleting = true;
    this.accountService.delete(account.id)
      .pipe(first())
      .subscribe({
        next: () => {
          console.log('Account deleted:', account.id);
          this.accounts = this.accounts.filter(x => x.id !== account.id);
          this.alertService.success('Account deleted successfully');
        },
        error: (error) => {
          console.error('Error deleting account:', error);
          account.isDeleting = false;
          const errorMessage = error.error?.message || 'Failed to delete account';
          this.alertService.error(errorMessage);
        }
      });
  }
}
